import{_ as e,o as s,c as a,an as t}from"./chunks/framework.Cjk6oCx_.js";const c=JSON.parse('{"title":"Writing a new modifier","description":"","frontmatter":{},"headers":[],"relativePath":"developer/extending.md","filePath":"developer/extending.md","lastUpdated":null}'),n={name:"developer/extending.md"};function o(r,i,d,l,h,p){return s(),a("div",null,[...i[0]||(i[0]=[t(`<h1 id="extending" tabindex="-1">Writing a new modifier <a class="header-anchor" href="#extending" aria-label="Permalink to &quot;Writing a new modifier {#extending}&quot;">​</a></h1><p>A modifier is a wrapper type around exactly one univariate distribution that changes one behaviour and delegates the rest. This page describes the pattern the built-in modifiers follow, using them as worked examples.</p><h2 id="The-shape-of-a-modifier" tabindex="-1">The shape of a modifier <a class="header-anchor" href="#The-shape-of-a-modifier" aria-label="Permalink to &quot;The shape of a modifier {#The-shape-of-a-modifier}&quot;">​</a></h2><ol start="2"><li><p><strong>A wrapper struct</strong> subtyping <code>UnivariateDistribution</code>, holding the inner distribution plus the modifier&#39;s parameters. Validate parameters in an inner constructor — see <code>Affine</code>&#39;s positive-scale check in <a href="https://github.com/EpiAware/ModifiedDistributions.jl/blob/main/src/Affine.jl" target="_blank" rel="noreferrer"><code>src/Affine.jl</code></a>.</p></li><li><p><strong>A lowercase constructor verb</strong> (<code>affine</code>, <code>weight</code>, <code>thin</code>, <code>modify</code>) as the user-facing entry point. If an &quot;absent&quot; parameter is meaningful, add a <code>::Nothing</code> passthrough method returning the distribution unchanged, as <code>weight(d, nothing)</code> and <code>thin(d, nothing)</code> do.</p></li><li><p><strong>A <code>get_dist</code> method</strong> exposing the inner distribution, one line:</p></li></ol><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_dist</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">MyWrapper</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dist</span></span></code></pre></div><p>This joins your wrapper to the unwrap protocol, so <code>get_dist_recursive</code> and downstream tooling work without knowing your type.</p><h2 id="Delegation" tabindex="-1">Delegation <a class="header-anchor" href="#Delegation" aria-label="Permalink to &quot;Delegation {#Delegation}&quot;">​</a></h2><p>Most methods should delegate to the inner distribution. For bulk delegation, <code>Transformed</code> uses an <code>@eval</code> loop worth copying:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> f </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:minimum</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:maximum</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:mean</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:median</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    :skewness</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:kurtosis</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:entropy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    @eval</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Distributions.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">$</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">f</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">MyWrapper</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Distributions.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">f</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dist)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span></span></code></pre></div><p>Then override only the methods your modifier actually changes (<code>logpdf</code> for a weight, the full change-of-variables set for an affine map). Remember <code>Base.eltype</code> — without it, batch sampling <code>rand(rng, d, n)</code> falls back to <code>Vector{Any}</code> and errors.</p><h2 id="Forward-transform-ops" tabindex="-1">Forward-transform ops <a class="header-anchor" href="#Forward-transform-ops" aria-label="Permalink to &quot;Forward-transform ops {#Forward-transform-ops}&quot;">​</a></h2><p>A new forward op (alongside <code>ThinOp</code>/<code>CumulativeOp</code>) does not need a new wrapper type. Implement <code>_apply_op(op, series)</code> and, if the op has a displayable parameter, <code>_op_params(op)</code>; then construct it with <code>series_transform(d, op)</code>.</p><h2 id="AD-friendliness" tabindex="-1">AD friendliness <a class="header-anchor" href="#AD-friendliness" aria-label="Permalink to &quot;AD friendliness {#AD-friendliness}&quot;">​</a></h2><p>Keep branches data-driven (on types and object identity), never on sampled parameter values, so gradients survive all backends. Add a gradient scenario for your modifier to <code>test/ADFixtures/src/ADFixtures.jl</code>, mirroring the existing entries — the AD CI sweeps it across ForwardDiff, ReverseDiff, Enzyme and Mooncake automatically.</p><h2 id="Checklist" tabindex="-1">Checklist <a class="header-anchor" href="#Checklist" aria-label="Permalink to &quot;Checklist {#Checklist}&quot;">​</a></h2><ul><li><p>[ ] Struct + validated inner constructor</p></li><li><p>[ ] Constructor verb (+ <code>Nothing</code> passthrough if applicable)</p></li><li><p>[ ] <code>get_dist</code> method</p></li><li><p>[ ] Delegations + overridden behaviour</p></li><li><p>[ ] <code>Base.eltype</code></p></li><li><p>[ ] Docstrings in the house style (<code>@doc</code> blocks, <code># Examples</code>, <code># See also</code>)</p></li><li><p>[ ] Export the verb; mark the type <code>public</code> in <code>src/public.jl</code></p></li><li><p>[ ] Tests in <code>test/MyWrapper.jl</code> + an ADFixtures scenario</p></li></ul>`,16)])])}const g=e(n,[["render",o]]);export{c as __pageData,g as default};
